def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority_sum = 0.0
        if ratio > 2:
            for k in range(1, int(ratio) + 2):
                term = ((ratio / k) ** 2) * np.exp(-k / ratio)
                priority_sum += term
            penalties = max(0, item - capacity) * 15
            priorities[i] = priority_sum + penalties
        elif 1 < ratio <= 2:
            try:
                priorities[i] = np.log(ratio * capacity + epsilon) * ratio ** 2
            except FloatingPointError:
                priorities[i] = np.inf
            if capacity % 2 == 0:
                priorities[i] *= 1.5
            else:
                priorities[i] *= 0.75
        elif 0.25 < ratio <= 1:
            summation = 0.0
            for n in range(1, int(capacity)+1):
                summation += ((-1) ** (n+1)) * ((ratio ** n) / n)
                if summation > 10:
                    break
            priorities[i] = summation + (item / (capacity + epsilon))
        else:
            power_sum = 0.0
            for m in range(1, 6):
                power_sum += (ratio ** m) / (m ** 2 + epsilon)
            priorities[i] = max(power_sum, 0.1)
            if capacity < item:
                priorities[i] += ((item - capacity) ** 2) * 5
        if capacities := bins[bins < capacity]:
            priorities[i] += np.sum((item / (capacities + epsilon)) ** 1.1)
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
